const items = $input.all();
const filtered = items.filter(item => {
  const status = (item.json.reply_status || '').trim().toLowerCase();
  const email  = (item.json.email || '').trim();
  return status === 'queued' && email !== '';
});
console.log(`[Filter] ${items.length} total → ${filtered.length} queued with email`);
if (filtered.length === 0) return [];
return filtered;

// Full prompt is documented in prompts/phase2_email_prompt.md
// This is the production prompt that generates Version A (professional with bullets)
// and Version B (casual punchy) per company.

const item = $('Split In Batches').item.json;
const websiteHtml = ($json.data || $json.body || '').toString();

// Strip HTML to clean text
const cleanText = websiteHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 3000);

const contactFirst = (item.contact_name || '').split(' ')[0].trim() || '';
const companyName  = item.company_name || 'Unknown Company';
const ycDescription = item.description || '';

// NOTE: Full 200+ line prompt in prompts/phase2_email_prompt.md
// Below is the abbreviated version. Replace with full prompt for production.
const p = [];
p.push('You write cold emails AS Dhwanil Doshi, a 21-year-old engineering student at Sarvajanik College of Engineering and Technology (SCET), Surat. Generate TWO versions per company.');
p.push('');
p.push('TARGET COMPANY:');
p.push('Name: ' + companyName);
p.push('YC pitch: ' + ycDescription);
p.push('Founder first name: ' + (contactFirst || '[NO NAME]'));
p.push('Website content: ' + cleanText);
p.push('');
p.push('RULES:');
p.push('1. ALWAYS open with "Hi [FirstName]," — never "Dear", never "Hii". If no name, use "Hi ' + companyName + ' team,"');
p.push('2. Banned: revolutionary, cutting-edge, leveraging, synergy, paradigm, holistic, ecosystem, journey, unlock, empower, innovative, transforming, exciting, thrilled, opportunity');
p.push('3. Reference SPECIFIC details from the website');
p.push('4. Match Dhwanil\'s projects to company domain: AI/data → Skilleton (3-agent pipeline, won DA-IICT 2100 teams). Frontend → CampusTwn (Three.js, 200+ users). Hardware → ESP32-C3 stress glove (90% accuracy, SIH 2025 finalist). Robotics → quadcopter + rover + FPGA. AI agents → JARVIS.');
p.push('');
p.push('VERSION A (professional, 200-280 words, bullets for technical companies, full signature with phone/email/LinkedIn).');
p.push('VERSION B (casual, 90-120 words, one personality line, signs off "Best, Dhwanil").');
p.push('');
p.push('Return ONLY this JSON:');
p.push('{"role_type": "fullstack|ml|embedded|general", "resume_type": "tailored|master", "matched_project": "A|B|C|D|E", "email_subject_A": "...", "email_body_A": "...", "email_subject_B": "...", "email_body_B": "..."}');

const promptText = p.join('\n');

return {
  json: {
    ...item,
    _ai_request: {
      model: 'gpt-4o',
      messages: [
        { role: 'system', content: 'You write cold emails for a confident technical 21-year-old engineering student. You hate buzzwords. Return only valid JSON.' },
        { role: 'user', content: promptText }
      ],
      temperature: 0.9,
      max_tokens: 2500,
      response_format: { type: 'json_object' }
    }
  }
};

const response = $json;
const company = $('Split In Batches').item.json;

const rawText = (response?.choices?.[0]?.message?.content || '').trim();

let jsonStr = rawText
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

const objMatch = jsonStr.match(/\{[\s\S]*\}/);
if (objMatch) jsonStr = objMatch[0];

let parsed = {};
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  console.error('[Parse] Failed: ' + jsonStr.substring(0, 200));
  parsed = {
    role_type: 'general', resume_type: 'master', matched_project: '',
    email_subject_A: 'Summer intern — ' + (company.company_name || ''),
    email_body_A: '[AI parse error — review manually]',
    email_subject_B: 'Summer intern — ' + (company.company_name || ''),
    email_body_B: '[AI parse error — review manually]'
  };
}

// Helper: convert escaped \n to real newlines, prevent formula injection
const clean = (str, max) => {
  if (!str) return '';
  let s = str.replace(/\\n/g, '\n').replace(/\\"/g, '"').trim().substring(0, max);
  if (['=','+','-','@'].includes(s[0])) s = "'" + s;
  return s;
};

const validRoles = ['fullstack', 'ml', 'embedded', 'general'];
const validResume = ['tailored', 'master'];
const validProjects = ['A', 'B', 'C', 'D', 'E'];

return {
  json: {
    email: company.email || '',
    company_name: company.company_name || '',
    role_type: validRoles.includes((parsed.role_type || '').toLowerCase()) ? parsed.role_type.toLowerCase() : 'general',
    resume_type: validResume.includes((parsed.resume_type || '').toLowerCase()) ? parsed.resume_type.toLowerCase() : 'master',
    matched_project: validProjects.includes((parsed.matched_project || '').toUpperCase()) ? parsed.matched_project.toUpperCase() : '',
    email_subject_A: clean(parsed.email_subject_A, 80),
    email_body_A: clean(parsed.email_body_A, 2000),
    email_subject_B: clean(parsed.email_subject_B, 80),
    email_body_B: clean(parsed.email_body_B, 2000),
    reply_status: 'drafted'
  }
};
